   221→}
   222→
   223→func (l *ClusterRoleBindingLister) ListClusterRoleBindings(ctx context.Context) ([]*rbacv1.ClusterRoleBinding, error) {
   224→	return l.Lister.List(labels.Everything())
   225→}
