All(ownerRule.ResourceNames, subRule.ResourceNames)\n\t}\n\n\treturn verbMatches && groupMatches && resourceMatches && resourceNameMatches && nonResourceURLMatches\n}\n", "numLines": 174, "startLine": 1, "totalLines": 174}}

